    /**
     * Find files matching the specified pattern
     *
     * @param searchDir   Path of the directory to search
     * @param filePattern Filename pattern (supports wildcards)
     * @return List of found files, one per line; returns error message on failure
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        if (searchDir == null || filePattern == null || searchDir.trim().isEmpty()) {
            return "Error: Search directory or file pattern is empty.";
        }

        // Construct bash command using positional parameters to avoid command injection
        // $1 is searchDir, $2 is filePattern (passed as separate arguments to bash)
        String cmdStr = "find \"$1\" -type f -name \"$2\" | head -n 10";
        String[] command = {"/bin/bash", "-c", cmdStr, "bash", searchDir, filePattern};

        Process process = null;
        try {
            // Execute command and assign to a final variable for lambda access
            final Process proc = Runtime.getRuntime().exec(command);
            process = proc;

            // Read stdout and stderr asynchronously to prevent deadlock
            // (Process can block if output/error buffers are not read while running)
            CompletableFuture<String> outputFuture = CompletableFuture.supplyAsync(() -> {
                try {
                    return readStream(proc.getInputStream());
                } catch (IOException e) {
                    throw new CompletionException("Failed to read output stream", e);
                }
            });

            CompletableFuture<String> errorFuture = CompletableFuture.supplyAsync(() -> {
                try {
                    return readStream(proc.getErrorStream());
                } catch (IOException e) {
                    throw new CompletionException("Failed to read error stream", e);
                }
            });

            // Wait for command execution to complete
            int exitCode = process.waitFor();

            // Retrieve stream contents
            String output, error;
            try {
                output = outputFuture.get();
                error = errorFuture.get();
            } catch (ExecutionException e) {
                // Unwrap the underlying exception
                Throwable cause = e.getCause();
                if (cause instanceof IOException) {
                    throw (IOException) cause;
                } else if (cause instanceof RuntimeException) {
                    throw (RuntimeException) cause;
                } else {
                    throw new RuntimeException("Unexpected error reading stream", cause);
                }
            }

            // Determine result based on exit code and output
            if (exitCode != 0) {
                // Command execution failed (e.g., invalid directory, permission denied)
                String errorMsg = error.isEmpty() ? output : error;
                return "Error: File search failed.\n" + errorMsg.trim();
            }

            if (output.isEmpty()) {
                return "No matching files found.";
            }

            return output.trim();
        } catch (IOException e) {
            return "Error: Exception occurred while executing command: " + e.getMessage();
        } catch (InterruptedException e) {
            // Restore interrupt status
            Thread.currentThread().interrupt();
            return "Error: File search was interrupted.";
        } finally {
            if (process != null) {
                // Ensure child process is terminated even if an exception occurs
                process.destroy();
            }
        }
    }

    /**
     * Helper method to read input stream and return as string
     *
     * @param inputStream Input stream
     * @return String read from the stream
     * @throws IOException On read error
     */
    private String readStream(InputStream inputStream) throws IOException {
        StringBuilder result = new StringBuilder();
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
            String line;
            while ((line = reader.readLine()) != null) {
                result.append(line).append("\n");
            }
        }
        return result.toString();
    }
